sql:
SELECT name
FROM training_staff
WHERE years_of_experience > 5;

SELECT AVG(years_of_experience) AS average_experience
FROM coaches
WHERE team_id = 1;

SELECT team_id, COUNT(staff_id) AS staff_count
FROM training_staff
GROUP BY team_id;

SELECT team_id, SUM(years_of_experience) AS total_experience
FROM medical_staff
GROUP BY team_id;

SELECT name
FROM training_staff
WHERE staff_id = 1;

SELECT COUNT(player_id) 
FROM player_stats 
WHERE season_id = 1;
